  function iso(value){ const ts = dateTs(value); return ts ? new Date(ts * 1000).toISOString() : new Date().toISOString(); }

  function normLot(raw = {}){ const quantity = Math.max(1, Math.floor(num(raw.quantity, 1))); const unitBuyPrice = num(raw.unitBuyPrice ?? raw.unitCost ?? raw.buyPrice); const totalBuyPrice = num(raw.totalBuyPrice ?? raw.totalCost, unitBuyPrice * quantity); const remainingQuantity = Math.min(quantity, Math.max(0, Math.floor(num(raw.remainingQuantity, quantity)))); return { ...raw, id: raw.id || id(), itemId: raw.itemId || undefined, itemName: String(raw.itemName || 'Unnamed item'), quantity, unitBuyPrice, unitCost: unitBuyPrice, buyPrice: unitBuyPrice, totalBuyPrice, totalCost: totalBuyPrice, remainingQuantity, createdAt: raw.createdAt || new Date().toISOString(), updatedAt: raw.updatedAt || new Date().toISOString(), notes: String(raw.notes || ''), source: raw.source || 'manual', originalLogId: raw.originalLogId ? String(raw.originalLogId) : undefined, logTypeId: raw.logTypeId ? Number(raw.logTypeId) : undefined, needsNameReview: Boolean(raw.needsNameReview) }; }
