  function normReview(raw = {}){ const entryId = String(raw.entryId || raw.originalLogId || raw.id || id()); return { ...raw, id: raw.id || `review-${entryId}`, entryId, originalLogId: entryId, logTypeId: raw.logTypeId ? Number(raw.logTypeId) : undefined, timestamp: raw.timestamp || raw.createdAt || new Date().toISOString(), type: raw.type === 'sell' ? 'sell' : 'buy', itemId: raw.itemId ? String(raw.itemId) : undefined, itemName: String(raw.itemName || ''), quantity: raw.quantity === undefined || raw.quantity === '' ? '' : num(raw.quantity), unitPrice: raw.unitPrice === undefined || raw.unitPrice === '' ? '' : num(raw.unitPrice), totalPrice: raw.totalPrice === undefined || raw.totalPrice === '' ? '' : num(raw.totalPrice), fees: raw.fees === undefined || raw.fees === '' ? '' : num(raw.fees), textPreview: String(raw.textPreview || raw.text || raw.message || '').slice(0, 320), rawKeys: Array.isArray(raw.rawKeys) ? raw.rawKeys.slice(0, 40) : [], rawSampleKeys: Array.isArray(raw.rawSampleKeys) ? raw.rawSampleKeys.slice(0, 40) : [], reason: String(raw.reason || 'Parser could not create a valid import candidate.'), source: 'api', ignored: Boolean(raw.ignored), createdAt: raw.createdAt || new Date().toISOString(), updatedAt: raw.updatedAt || raw.createdAt || new Date().toISOString() }; }
