  function normalizeData(raw = {}){ const base = defaults(); const settings = { ...base.settings, ...(raw.settings || {}) }; settings.apiEnabled = Boolean(settings.apiEnabled && settings.apiKey); settings.apiStatus = settings.apiEnabled ? settings.apiStatus || 'ready' : 'disabled'; return { ...base, ...raw, settings, windowState: raw.windowState && typeof raw.windowState === 'object' ? { ...base.windowState, ...raw.windowState } : base.windowState, purchaseLots: Array.isArray(raw.purchaseLots) ? raw.purchaseLots.map(normLot) : [], sales: Array.isArray(raw.sales) ? raw.sales.map(normSale) : [], itemPriceSnapshots: Array.isArray(raw.itemPriceSnapshots) ? raw.itemPriceSnapshots : [], importedLogIds: Array.isArray(raw.importedLogIds) ? [...new Set(raw.importedLogIds.map(String))] : [], importReviewQueue: Array.isArray(raw.importReviewQueue) ? raw.importReviewQueue.map(normReview).slice(0, 100) : [], importHistory: Array.isArray(raw.importHistory) ? raw.importHistory.slice(0, 30) : [], backups: Array.isArray(raw.backups) ? raw.backups : [] }; }
  function readJson(name, fallback){ try{ const raw = localStorage.getItem(name); return raw ? JSON.parse(raw) : fallback; } catch(error){ return fallback; } }
  function load(){ const saved = readJson(storageKey(), null); const raw = saved || { sales: readJson(legacyKey('flips'), []), purchaseLots: readJson(legacyKey('openPurchases'), []), windowState: readJson(legacyKey('windowState'), readJson(legacyKey('windowPosition'), {})) }; const data = normalizeData(raw); save(data); return data; }
