  function remaining(lot){ return Math.max(0, num(lot.remainingQuantity, lot.quantity)); }
  function matchingLots(lots, sale){ const name = String(sale.itemName || '').toLowerCase(); const itemId = sale.itemId ? String(sale.itemId) : ''; return lots.filter((lot) => remaining(lot) > 0 && ((itemId && String(lot.itemId || '') === itemId) || String(lot.itemName || '').toLowerCase() === name)).sort((a,b) => String(a.createdAt).localeCompare(String(b.createdAt))); }
  function matchSale(lots, sale, settings = {}){ const quantity = Math.max(1, Math.floor(num(sale.quantity, 1))); const totalSellPrice = sale.totalSellPrice !== undefined ? num(sale.totalSellPrice) : num(sale.unitSellPrice ?? sale.sellPrice) * quantity; const unitSellPrice = quantity ? totalSellPrice / quantity : num(sale.unitSellPrice ?? sale.sellPrice); let left = quantity; let matchedBuyCost = 0; let matchedQuantity = 0; const matchedLots = []; matchingLots(lots, sale).forEach((lot) => { if(left <= 0) return; const qty = Math.min(remaining(lot), left); const cost = qty * num(lot.unitBuyPrice ?? lot.buyPrice); matchedBuyCost += cost; matchedQuantity += qty; left -= qty; matchedLots.push({ lotId: lot.id, quantity: qty, unitBuyPrice: num(lot.unitBuyPrice ?? lot.buyPrice), totalBuyPrice: cost }); }); const unmatchedQuantity = Math.max(0, left); if(sale.manualBuyCostOverride) matchedBuyCost += num(sale.buyPrice) * unmatchedQuantity; const fees = sale.fees === undefined || sale.fees === '' ? totalSellPrice * num(settings.bazaarFeeRate, 0.03) : num(sale.fees); const grossProfit = unmatchedQuantity > 0 && matchedQuantity === 0 && !sale.manualBuyCostOverride ? 0 : totalSellPrice - matchedBuyCost; const netProfit = unmatchedQuantity > 0 && matchedQuantity === 0 && !sale.manualBuyCostOverride ? 0 : grossProfit - fees; const roi = matchedBuyCost > 0 ? netProfit / matchedBuyCost * 100 : 0; return normSale({ ...sale, quantity, unitSellPrice, totalSellPrice, matchedQuantity, unmatchedQuantity, matchedBuyCost, grossProfit, fees, netProfit, roi, matchedLots, unmatchedSale: unmatchedQuantity > 0, soldAt: sale.soldAt || new Date().toISOString() }); }
  function applySale(lots, saleRecord){ const used = {}; (saleRecord.matchedLots || []).forEach((m) => { used[m.lotId] = (used[m.lotId] || 0) + num(m.quantity); }); return lots.map((lot) => used[lot.id] ? { ...lot, remainingQuantity: Math.max(0, remaining(lot) - used[lot.id]), updatedAt: new Date().toISOString() } : lot); }
  function saveSaleCandidate(data, lots, sales, candidate){ const sale = matchSale(lots, candidate, data.settings); const warning = sale.unmatchedQuantity > 0 ? `${sale.itemName}: ${sale.unmatchedQuantity} sold item(s) could not be matched to open purchases.` : ''; const record = normSale({ ...sale, originalLogId: candidate.originalLogId, logTypeId: candidate.logTypeId, unmatchedSale: sale.unmatchedQuantity > 0, importWarning: warning, notes: warning || sale.notes || candidate.notes || 'Imported from Torn log' }); return { lots: applySale(lots, record), sales: [record, ...sales], warning, unmatched: Boolean(warning) }; }

  function portfolio(data = load()){ const groups = {}; (data.purchaseLots || []).forEach((lot) => { const qty = remaining(lot); if(qty <= 0) return; const key = lot.itemId ? `id:${lot.itemId}` : `name:${String(lot.itemName).toLowerCase()}`; groups[key] = groups[key] || { itemId: lot.itemId || '', itemName: lot.itemName, quantity: 0, totalInvestment: 0 }; groups[key].quantity += qty; groups[key].totalInvestment += qty * num(lot.unitBuyPrice ?? lot.buyPrice); }); return Object.values(groups).map((item) => { const avg = item.quantity ? item.totalInvestment / item.quantity : 0; const fee = Math.max(0.0001, 1 - num(data.settings.bazaarFeeRate, 0.03)); const target = (avg * (1 + num(data.settings.targetRoi, 20) / 100)) / fee; const profit = target * item.quantity * fee - item.totalInvestment; return { ...item, averageCost: avg, breakEvenSellPrice: avg / fee, targetSellPrice: target, estimatedProfit: profit, estimatedROI: item.totalInvestment ? profit / item.totalInvestment * 100 : 0 }; }); }
  function stats(data = load()){ const sales = data.sales || []; const lots = data.purchaseLots || []; const now = new Date(); const day = new Date(now.getFullYear(), now.getMonth(), now.getDate()).getTime(); const week = new Date(now.getFullYear(), now.getMonth(), now.getDate() - ((now.getDay() || 7) - 1)).getTime(); const month = new Date(now.getFullYear(), now.getMonth(), 1).getTime(); const profitSince = (time) => sales.reduce((sum, sale) => Date.parse(sale.soldAt || sale.createdAt || '') >= time ? sum + num(sale.netProfit ?? sale.profit) : sum, 0); const lifetimeProfit = sales.reduce((sum, sale) => sum + num(sale.netProfit ?? sale.profit), 0); const totalBuy = sales.reduce((sum, sale) => sum + num(sale.matchedBuyCost ?? sale.totalBuy), 0); return { totalTrades:sales.length, totalInvestment: lots.reduce((sum, lot) => sum + remaining(lot) * num(lot.unitBuyPrice ?? lot.buyPrice), 0), lifetimeProfit, todayProfit:profitSince(day), weeklyProfit:profitSince(week), monthlyProfit:profitSince(month), averageROI: totalBuy ? lifetimeProfit / totalBuy * 100 : 0, bestFlip:[...sales].sort((a,b) => num(b.netProfit) - num(a.netProfit))[0] || null, worstFlip:[...sales].sort((a,b) => num(a.netProfit) - num(b.netProfit))[0] || null }; }

  function addItemName(map, itemId, itemName){ const idText = itemId === undefined || itemId === null || itemId === '' ? '' : String(itemId); const name = String(itemName || '').trim(); if(idText && name && !/^Item #\d+$/i.test(name)) map.set(idText, name); }
  function scanItems(value, map, depth = 0){ if(!value || depth > 4) return; if(Array.isArray(value)){ value.slice(0,5000).forEach((entry) => scanItems(entry, map, depth + 1)); return; } if(typeof value !== 'object') return; Object.entries(value).slice(0,5000).forEach(([key, entry]) => { if(entry && typeof entry === 'object'){ addItemName(map, entry.itemId || entry.item_id || entry.id || (/^\d+$/.test(key) ? key : ''), entry.itemName || entry.item_name || entry.name || entry.title); scanItems(entry.items || entry.data || entry.children, map, depth + 1); } else if(/^\d+$/.test(key) && typeof entry === 'string') addItemName(map, key, entry); }); }
  function itemLookup(data){ const map = new Map(); (data.itemPriceSnapshots || []).forEach((snapshot) => addItemName(map, snapshot.itemId, snapshot.itemName)); scanItems(data.items, map); scanItems(data.tornItems, map); scanItems(data.settings && data.settings.itemMap, map); return { resolve(itemId, fallbackName = ''){ const idText = itemId === undefined || itemId === null || itemId === '' ? '' : String(itemId); const given = String(fallbackName || '').trim(); const cached = idText ? map.get(idText) || '' : ''; const itemName = given || cached || (idText ? `Item #${idText}` : ''); return { itemId: idText || undefined, itemName, needsNameReview: Boolean(idText && !given && !cached) }; } }; }
